import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;
import io.github.resilience4j.retry.annotation.Retry;
import org.springframework.stereotype.Service;
import java.util.*;

@Service
public class MarketDataService {
    private final MarketClient client;
    MarketDataService(MarketClient c) { client = c; }

    // @Retry inside @CircuitBreaker:
    // Retry is the inner layer, CB is the outer layer
    @CircuitBreaker(name = "market-data", fallbackMethod = "getQuotesFallback")
    @Retry(name = "market-data")
    public List<StockQuote> getQuotes(List<String> symbols) {
        return client.getQuotes(symbols);
    }

    public List<StockQuote> getQuotesFallback(List<String> symbols, Exception ex) {
        System.out.printf("[FALLBACK] getQuotes(%s): %s%n", symbols, ex.getMessage());
        return Collections.emptyList();  // empty list — caller handles gracefully
    }
}

// application.properties:
// resilience4j.retry.instances.market-data.max-attempts=3
// resilience4j.retry.instances.market-data.wait-duration=500ms
