import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;
import org.springframework.stereotype.Service;
import java.util.concurrent.ConcurrentHashMap;
import java.util.Map;

@Service
public class StockPriceService {
    private final MarketClient marketClient;
    private final Map<String, Double> priceCache = new ConcurrentHashMap<>();

    StockPriceService(MarketClient mc) { marketClient = mc; }

    @CircuitBreaker(name = "market-service",
                    fallbackMethod = "getPriceFallback")
    public double getPrice(String symbol) {
        double price = marketClient.getPrice(symbol);
        priceCache.put(symbol, price);  // update cache on success
        return price;
    }

    public double getPriceFallback(String symbol, Exception ex) {
        double cached = priceCache.getOrDefault(symbol, 0.0);
        System.out.printf("[FALLBACK/CACHED] %s: using cached price %.2f (%s)%n",
            symbol, cached,
            cached == 0.0 ? "no cache" : "CACHED");
        return cached;
    }

    // Helper for tests:
    public void warmCache(String symbol, double price) {
        priceCache.put(symbol, price);
    }
}

