@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.NONE)
@TestPropertySource(properties = "eureka.client.enabled=false")
class StockPriceServiceFallbackTest {
    @MockBean MarketClient marketClient;
    @Autowired StockPriceService stockPriceService;
    @Autowired CircuitBreakerRegistry circuitBreakerRegistry;

    @BeforeEach void resetCircuit() {
        circuitBreakerRegistry.circuitBreaker("market-service").reset();
    }

    @Test
    void getPrice_marketClientFails_returnsFallback() {
        when(marketClient.getPrice("TCS"))
            .thenThrow(new RuntimeException("market-service down"));

        double price = stockPriceService.getPrice("TCS");

        // Fallback: no cache → returns 0.0
        assertEquals(0.0, price, 0.001);
        // marketClient was called once (CB hasn't opened yet):
        verify(marketClient, times(1)).getPrice("TCS");
    }

    @Test
    void getPrice_withCachedValue_returnsCachedOnFallback() {
        // Pre-warm the cache:
        stockPriceService.warmCache("TCS", 3890.0);
        when(marketClient.getPrice("TCS"))
            .thenThrow(new RuntimeException("service down"));

        double price = stockPriceService.getPrice("TCS");
        assertEquals(3890.0, price, 0.001);  // cached value returned
    }
}

