@SpringBootTest(webEnvironment=SpringBootTest.WebEnvironment.NONE)
@TestPropertySource(properties={
    "eureka.client.enabled=false",
    "resilience4j.circuitbreaker.instances.market-service.sliding-window-size=5",
    "resilience4j.circuitbreaker.instances.market-service.minimum-number-of-calls=3",
    "resilience4j.circuitbreaker.instances.market-service.failure-rate-threshold=60",
    "resilience4j.circuitbreaker.instances.market-service.wait-duration-in-open-state=10s"
})
class CircuitBreakerOpenTest {
    @MockBean MarketClient marketClient;
    @Autowired StockPriceService svc;
    @Autowired CircuitBreakerRegistry registry;

    @BeforeEach void reset() { registry.circuitBreaker("market-service").reset(); }

    @Test
    void circuit_opensAfterThreshold_subsequentCallsSkipClient() {
        when(marketClient.getPrice(anyString()))
            .thenThrow(new RuntimeException("service down"));

        // 5 failures to exceed 60% of 5-call window:
        for (int i = 0; i < 5; i++) svc.getPrice("TCS");

        // Circuit should be OPEN now:
        assertEquals(CircuitBreaker.State.OPEN,
            registry.circuitBreaker("market-service").getState());

        // Reset call count:
        clearInvocations(marketClient);

        // Next call — circuit is OPEN, fallback returned without calling client:
        double price = svc.getPrice("TCS");
        assertEquals(0.0, price, 0.001);  // fallback
        verify(marketClient, never()).getPrice(anyString());  // NOT called!
    }
}

