import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;
import org.springframework.stereotype.Service;
record OrderStatus(String orderId, String status, String source) {}
class ResourceNotFoundException extends RuntimeException { ResourceNotFoundException(String m){super(m);} }

interface OrderClient { OrderStatus getOrderStatus(String orderId); }

@Service
public class OrderService {
    private final OrderClient client;
    OrderService(OrderClient c) { client = c; }

    @CircuitBreaker(name = "order-service", fallbackMethod = "getStatusFallback")
    public OrderStatus getOrderStatus(String orderId) {
        return client.getOrderStatus(orderId);
    }

    // Most specific first: ResourceNotFoundException
    public OrderStatus getStatusFallback(String orderId,
            ResourceNotFoundException ex) {
        System.out.println("Order not found: " + orderId);
        return new OrderStatus(orderId, "NOT_FOUND", "FALLBACK");
    }

    // General fallback: any other Exception
    public OrderStatus getStatusFallback(String orderId, Exception ex) {
        System.out.println("Order service error for " + orderId + ": " + ex.getMessage());
        return new OrderStatus(orderId, "UNKNOWN", "FALLBACK");
    }
    // Resilience4j matches: most specific exception type first
}

