@Service
public class SmsService {
    private final SmsClient smsClient;
    private final Queue<String[]> retryQueue = new ConcurrentLinkedQueue<>();

    SmsService(SmsClient sc) { smsClient = sc; }

    @RateLimiter(name = "sms-gateway", fallbackMethod = "smsFallback")
    public void sendSms(String phone, String message) {
        smsClient.send(phone, message);
        System.out.println("SMS sent to " + phone);
    }

    public void smsFallback(String phone, String message, 
            io.github.resilience4j.ratelimiter.RequestNotPermitted ex) {
        System.out.printf("[RATE LIMITED] SMS to %s queued for retry%n", phone);
        retryQueue.offer(new String[]{phone, message});
    }

    public Queue<String[]> getRetryQueue() { return retryQueue; }
}

