import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;
import io.github.resilience4j.retry.annotation.Retry;
import org.springframework.stereotype.Service;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

class UserVerificationUnavailableException extends RuntimeException{ UserVerificationUnavailableException(String m){super(m);} }
class PaymentUnavailableException extends RuntimeException{ PaymentUnavailableException(String m){super(m);} }
record Quote(String symbol, double price, boolean tradeable) {}
record TradeResult(String orderId, String symbol, int qty, double total) {}

@Service
public class TradeOrchestrationService {
    private final MarketClient marketClient;
    private final UserClient userClient;
    private final PaymentClient paymentClient;
    private final Map<String,Double> priceCache = new ConcurrentHashMap<>();

    TradeOrchestrationService(MarketClient m, UserClient u, PaymentClient p){ marketClient=m; userClient=u; paymentClient=p; }

    @CircuitBreaker(name="market", fallbackMethod="quoteFallback") @Retry(name="market")
    public Quote getMarketQuote(String symbol) {
        Quote q = marketClient.getQuote(symbol); priceCache.put(symbol, q.price()); return q;
    }
    Quote quoteFallback(String symbol, Exception ex) {
        return new Quote(symbol, priceCache.getOrDefault(symbol,0.0), false);
    }

    @CircuitBreaker(name="user", fallbackMethod="verifyFallback")
    public boolean verifyUser(String userId) { return userClient.isActive(userId); }
    boolean verifyFallback(String userId, Exception ex) {
        throw new UserVerificationUnavailableException("Cannot verify user: circuit open");
    }

    @CircuitBreaker(name="payment", fallbackMethod="chargeFallback")
    public String chargePayment(String userId, double amount) { return paymentClient.charge(userId, amount); }
    String chargeFallback(String userId, double amount, Exception ex) {
        throw new PaymentUnavailableException("Payment service unavailable");
    }

    public TradeResult executeTrade(String userId, String symbol, int qty) {
        if (!verifyUser(userId)) throw new IllegalStateException("User not active");
        Quote q = getMarketQuote(symbol);
        if (!q.tradeable()) throw new IllegalStateException(symbol + " not tradeable");
        String payId = chargePayment(userId, q.price() * qty);
        return new TradeResult("TRD-"+payId, symbol, qty, q.price()*qty);
    }
}

