    "resilience4j.circuitbreaker.instances.market-service.minimum-number-of-calls=3",
    "resilience4j.circuitbreaker.instances.market-service.failure-rate-threshold=60",
    "resilience4j.circuitbreaker.instances.market-service.permitted-number-of-calls-in-half-open-state=2"
})
class CircuitHalfOpenTest {
    @MockBean MarketClient marketClient;
    @Autowired StockPriceService svc;
    @Autowired CircuitBreakerRegistry registry;

    @BeforeEach void reset() { registry.circuitBreaker("market-service").reset(); }

    @Test
    void circuit_recovers_closedAfterHalfOpenSuccess() {
        CircuitBreaker cb = registry.circuitBreaker("market-service");

        // Step 1: Open the circuit with failures
        when(marketClient.getPrice(anyString())).thenThrow(new RuntimeException("down"));
        for (int i = 0; i < 5; i++) svc.getPrice("TCS");
        assertEquals(CircuitBreaker.State.OPEN, cb.getState());

        // Step 2: Manually transition to HALF-OPEN (avoid Thread.sleep in test)
        cb.transitionToHalfOpenState();
        assertEquals(CircuitBreaker.State.HALF_OPEN, cb.getState());

        // Step 3: Successful calls in HALF-OPEN
        when(marketClient.getPrice("TCS")).thenReturn(3890.0);
        svc.getPrice("TCS");  // test call 1 — success
        svc.getPrice("TCS");  // test call 2 — success (permitted-calls=2)

        // Step 4: Circuit should be CLOSED now
        assertEquals(CircuitBreaker.State.CLOSED, cb.getState());
    }
}

