import org.springframework.stereotype.Service;
import java.util.*;
import java.util.concurrent.*;

record Price(String symbol, double value, boolean live) {}
class AccountRateLimitedException extends RuntimeException{ AccountRateLimitedException(String m){super(m);} }

@Service class PriceService {
    private final Map<String,Double> cache=new ConcurrentHashMap<>();
    @CircuitBreaker(name="market",fallbackMethod="fallback") @Retry(name="market")
    public Price getPrice(String sym) {
        // simulate market call
        if(sym.equals("FAIL")) throw new RuntimeException("Market down");
        double p=sym.equals("TCS")?3890.0:1560.0; cache.put(sym,p); return new Price(sym,p,true);
    }
    Price fallback(String sym,Exception ex){ return new Price(sym,cache.getOrDefault(sym,0.0),false); }
}

@Service class AccountService {
    @RateLimiter(name="account",fallbackMethod="rateFallback")
    @CircuitBreaker(name="account",fallbackMethod="cbFallback")
    public boolean isAccountActive(String userId){
        if(userId.equals("U99")) throw new RuntimeException("Account svc down");
        return true;
    }
    boolean rateFallback(String uid,io.github.resilience4j.ratelimiter.RequestNotPermitted ex){
        throw new AccountRateLimitedException("Account verification rate limited");
    }
    boolean cbFallback(String uid,Exception ex){ throw new RuntimeException("Account CB: "+ex.getMessage()); }
}

@Service class TradeExecutionService {
    private final PriceService priceService; private final AccountService accountService;
    TradeExecutionService(PriceService p, AccountService a){priceService=p;accountService=a;}
    public String executeTrade(String userId,String symbol,int qty){
        if(!accountService.isAccountActive(userId)) throw new IllegalStateException("Inactive account");
        Price p=priceService.getPrice(symbol);
        if(!p.live()) throw new IllegalStateException(symbol+" price not live — using cache");
        return "TRD-"+symbol+"-"+qty+"@"+p.value();
    }
}

